    const group = new THREE.Group();
    group.userData.bimPickId = wall.id;

    // Glass infill panels — one large pane per bay (subdivided by mullions below)
    const glassMat = new THREE.MeshStandardMaterial({
      color: 0x88ccee,
      transparent: true,
      opacity: 0.32,
      roughness: 0.05,
